import "core-js/modules/es.iterator.for-each.js";
import LogPanel from '@/components/LogPanel.vue';
import ServiceStatus from '@/components/ServiceStatus.vue';
import { validateImage, fileToDataURL, getImageDimensions, formatFileSize } from '@/utils/imageUtils';
import { analyzeImageMock as analyzeImage, checkHealth } from '@/api/pigModel';
document.querySelectorAll('.glow-hover').forEach(el => {
  el.addEventListener('mousemove', e => {
    const rect = el.getBoundingClientRect();
