export default {
  name: 'App',
  components: {
    LogPanel,
    ServiceStatus
  },
  data() {
    return {
      checkingService: false,
      isDragging: false,
      hoveredBox: null,
      animatedCount: 0
    };
  },
  computed: {
    hasImage() {
      return this.$store.getters.hasImage;
    },
    hasResult() {
      return this.$store.getters.hasResult;
    },
    previewUrl() {
      return this.$store.state.previewUrl;
    },
    imageMeta() {
      return this.$store.state.imageMeta;
    },
    isAnalyzing() {
      return this.$store.state.isAnalyzing;
    },
    uploadProgress() {
      return this.$store.state.uploadProgress;
    },
    result() {
      return this.$store.state.result;
    },
    pigCount() {
      return this.$store.getters.pigCount;
    },
    confidencePct() {
      return this.$store.getters.confidencePct;
    },
    inferenceTime() {
      return this.$store.getters.inferenceTime;
    },
    year() {
      return new Date().getFullYear();
    },
    confClass() {
      const p = this.confidencePct;
      if (p >= 85) return 'conf-high';
      if (p >= 65) return 'conf-mid';
      return 'conf-low';
    }
  },
  watch: {
    pigCount(val) {
      if (val === null) {
        this.animatedCount = 0;
        return;
      }
      this.animateNumber(val);
    },
    hasResult(val) {
      if (val) this.$nextTick(() => this.drawBoxes());
    }
  },
  mounted() {
    this.initGlowEffect();
  },
  created() {
    this.checkServiceHealth();
  },
  methods: {
    /* ---- File handling ---- */
    onTopFileChange(e) {
      const f = e.target.files[0];
      if (f) this.processFile(f);
      e.target.value = '';
    },
    onDropInputChange(e) {
      const f = e.target.files[0];
      if (f) this.processFile(f);
      e.target.value = '';
    },
    onDrop(e) {
      this.isDragging = false;
      const f = e.dataTransfer.files[0];
      if (f) this.processFile(f);
    },
    async processFile(file) {
      const {
        valid,
        error
      } = validateImage(file);
      if (!valid) {
        this.$store.commit('ADD_LOG', {
          msg: error,
          type: 'error'
        });
        return;
      }
      const dataURL = await fileToDataURL(file);
      const dimensions = await getImageDimensions(dataURL);
      const meta = {
        name: file.name,
        size: formatFileSize(file.size),
        width: dimensions.width,
        height: dimensions.height
      };
      this.$store.commit('SET_IMAGE', {
        file,
        previewUrl: dataURL,
        meta
      });
      this.$store.commit('ADD_LOG', {
        msg: `已加载：${file.name}（${meta.size}，${meta.width}×${meta.height}）`,
        type: 'info'
      });
    },
    clearImage() {
      this.$store.commit('CLEAR_IMAGE');
      this.$store.commit('ADD_LOG', {
        msg: '已清除图片',
        type: 'info'
      });
      this.clearCanvas();
    },
    /* ---- Analysis ---- */
    async runAnalysis() {
      if (!this.hasImage || this.isAnalyzing) return;
      this.$store.commit('SET_ANALYZING', true);
      this.$store.commit('SET_PROGRESS', 0);
      this.$store.commit('ADD_LOG', {
        msg: '发送至数猪大模型...',
        type: 'info'
      });
      try {
        const result = await analyzeImage(this.$store.state.imageFile, p => this.$store.commit('SET_PROGRESS', p));
        this.$store.commit('SET_RESULT', result);
        this.$store.commit('SET_PROGRESS', 100);
        this.$store.commit('ADD_LOG', {
          msg: `识别完成：检测到 ${result.count} 头猪`,
          type: 'success'
        });
        this.$store.commit('ADD_LOG', {
          msg: `置信度 ${Math.round(result.confidence * 100)}%` + (result.inferenceTime ? `  耗时 ${result.inferenceTime}ms` : ''),
          type: 'success'
        });
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: `识别失败：${err.message}`,
          type: 'error'
        });
      } finally {
        this.$store.commit('SET_ANALYZING', false);
      }
    },
    /* ---- Canvas bounding boxes ---- */
    drawBoxes() {
      const canvas = this.$refs.boxCanvas;
      const img = this.$refs.baseImg;
      if (!canvas || !img || !this.hasResult) return;
      const boxes = this.result?.boxes || [];
      canvas.width = img.clientWidth;
      canvas.height = img.clientHeight;
      const ctx = canvas.getContext('2d');
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      const scaleX = canvas.width;
      const scaleY = canvas.height;
      boxes.forEach((box, i) => {
        // box coords are 0~1 normalized OR pixel coords — handle both
        const isNorm = box.x1 <= 1 && box.y1 <= 1;
        const x1 = isNorm ? box.x1 * scaleX : box.x1 / (this.imageMeta?.width || 1) * scaleX;
        const y1 = isNorm ? box.y1 * scaleY : box.y1 / (this.imageMeta?.height || 1) * scaleY;
        const x2 = isNorm ? (box.x1 + box.x2) * scaleX : box.x2 / (this.imageMeta?.width || 1) * scaleX;
        const y2 = isNorm ? (box.y1 + box.y2) * scaleY : box.y2 / (this.imageMeta?.height || 1) * scaleY;
        const isHovered = this.hoveredBox === i;
        ctx.strokeStyle = isHovered ? '#f4a24a' : '#39e879';
        ctx.lineWidth = isHovered ? 2.5 : 1.5;
        ctx.strokeRect(x1, y1, x2 - x1, y2 - y1);

        // Label
        const label = `${i + 1} ${(box.score * 100).toFixed(0)}%`;
        ctx.font = 'bold 11px monospace';
        const tw = ctx.measureText(label).width;
        ctx.fillStyle = isHovered ? '#f4a24a' : '#39e879';
        ctx.fillRect(x1, y1 - 18, tw + 8, 18);
        ctx.fillStyle = '#000';
        ctx.fillText(label, x1 + 4, y1 - 4);
      });
    },
    clearCanvas() {
      const canvas = this.$refs.boxCanvas;
      if (canvas) canvas.getContext('2d').clearRect(0, 0, canvas.width, canvas.height);
    },
    /* ---- Helpers ---- */
    animateNumber(target) {
      const dur = 700,
        start = Date.now(),
        from = 0;
      const tick = () => {
        const t = Math.min((Date.now() - start) / dur, 1);
        this.animatedCount = Math.round(from + (target - from) * (1 - Math.pow(1 - t, 3)));
        if (t < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    },
    getConfClass(score) {
      if (score >= 0.85) return 'conf-high';
      if (score >= 0.65) return 'conf-mid';
      return 'conf-low';
    },
    formatCoord(box) {
      const isNorm = box.x1 <= 1 && box.y1 <= 1;
      if (isNorm) {
        const w = this.imageMeta?.width || 1;
        const h = this.imageMeta?.height || 1;
        return `${Math.round(box.x1 * w)}, ${Math.round(box.y1 * h)}, ${Math.round((box.x1 + box.x2) * w)}, ${Math.round((box.y1 + box.y2) * h)}`;
      }
      return `${Math.round(box.x1)}, ${Math.round(box.y1)}, ${Math.round(box.x2)}, ${Math.round(box.y2)}`;
    },
    async checkServiceHealth() {
      this.checkingService = true;
      this.$store.commit('ADD_LOG', {
        msg: '检测模型服务状态...',
        type: 'info'
      });
      try {
        const online = await checkHealth();
        this.$store.commit('SET_SERVICE_STATUS', online);
        this.$store.commit('ADD_LOG', {
          msg: online ? '模型服务在线' : '服务未响应（使用 Mock 模式）',
          type: online ? 'success' : 'warn'
        });
      } catch {
        this.$store.commit('SET_SERVICE_STATUS', false);
      } finally {
        this.checkingService = false;
      }
    }
  }
};
